[Fact]
public void Table_ShouldAllowCreationManuallyAndFromPocoCollections()
{
    // Manual Creation Test
    var manualTable = new ConsoleTable("Col1", "Col2");
    manualTable.AddRow("Value1", "Value2");

    Assert.Equal(2, manualTable.Columns.Count);
    Assert.Equal("Col1", manualTable.Columns[0]);
    Assert.Single(manualTable.Rows);
    Assert.Equal("Value1", manualTable.Rows[0][0]);

    // Automatic Generation from POCOs Test
    var users = new List<User>
    {
        new User { Name = "TestUser", Age = 30 }
    };

    var autoTable = ConsoleTable.From(users);

    // Verify columns were generated from POCO property names
    Assert.Contains("Name", autoTable.Columns);
    Assert.Contains("Age", autoTable.Columns);
    Assert.Single(autoTable.Rows);

    // Verify row data was mapped correctly
    var nameIndex = autoTable.Columns.IndexOf("Name");
    var ageIndex = autoTable.Columns.IndexOf("Age");
    Assert.Equal("TestUser", autoTable.Rows[0][nameIndex]);
    Assert.Equal(30, autoTable.Rows[0][ageIndex]);
}

[Fact]
public void ShouldApplyVisualStylesAndAlignmentConfigurationToOutput()
{
    var writer = new System.IO.StringWriter();
    var table = new ConsoleTable("Header")
        .AddRow(123)
        .Configure(config =>
        {
            config.NumberAlignment = Alignment.Right;
            config.OutputTo = writer;
            config.EnableCount = false;
        });

    // Exercise the customization via a predefined visual style
    table.Write(Format.Minimal);
    var output = writer.ToString();

    // Assert that the configuration was applied correctly
    Assert.Equal(Alignment.Right, table.Options.NumberAlignment);
    Assert.False(table.Options.EnableCount);
    Assert.Equal(writer, table.Options.OutputTo);

    // Verify the output contains expected content
    Assert.Contains("Header", output);
    Assert.Contains("123", output);
    Assert.DoesNotContain("Count:", output);
}

[Fact]
public void AddRow_ShouldValidateColumnsExistAndCountMatches()
{
    var table = new ConsoleTable();

    var missingColumnsException = Assert.Throws<Exception>(() => table.AddRow("Test Value"));
    Assert.Equal("Please set the columns first", missingColumnsException.Message);

    table.AddColumn(new[] { "Column1", "Column2" });

    var countMismatchException = Assert.Throws<Exception>(() => table.AddRow("Single Value"));
    Assert.Contains("does not match the values", countMismatchException.Message);

    table.AddRow("Value 1", "Value 2");
    Assert.Single(table.Rows);
}

[Fact]
public void ShouldWrapCellContentAtWordBreakDelimiterToPreventMidWordSplits()
{
    // Arrange
    var table = new ConsoleTable("Header");
    table.MaxWidth = 10;
    // "Split HereNow" is 13 characters. With MaxWidth 10, the cut at index 10 ("Split Here") 
    // falls between 'e' and 'N'. Neither is a space, so it should look back for the WordBreakDelimiter (' ').
    table.AddRow("Split HereNow");

    // Act
    var result = table.ToString();

    // Assert
    // The original column length (before splitting) is 13. 
    // The Header "Header" (6) and Row "Split HereNow" (13) result in a column length of 13.
    // Header formatted: " | Header        |" (1 + 1 + 1 + 13 + 1 + 1 = 18 chars).
    // Divider: 18 - 1 = 17 dashes.
    // Word wrap logic: 
    // 1. "Split Here" (10 chars). Last space is at index 5.
    // 2. Row 1 becomes "Split", Row 2 becomes "HereNow".
    var expected = """
                    ----------------- 
                    | Header        |
                    ----------------- 
                    | Split         |
                    ----------------- 
                    | HereNow       |
                    ----------------- 

                    Count: 2
                   """.Replace("\r\n", "\n");

    Assert.Equal(expected, result.Replace("\r\n", "\n"));
}

[Fact]
public void TableAlignmentShouldAccountForUnicodeVisualWidths()
{
    // Arrange
    // "Header" visual width = 6
    // "ABC" visual width = 3
    // "你好" visual width = 4 (assuming 2 units per character as per UnicodeCalculator evidence)
    var table = new ConsoleTable("Header");
    table.AddRow("ABC");
    table.AddRow("你好");

    // Act
    var result = table.ToString().Replace("\r\n", "\n");

    // Assert
    // The column width is set by "Header" (6).
    // "ABC" (width 3) needs 3 spaces to align to 6, plus 1 mandatory padding space = 4 spaces total.
    // "你好" (width 4) needs 2 spaces to align to 6, plus 1 mandatory padding space = 3 spaces total.
    // If the library used string.Length (2), it would have added 4 spaces for "你好", breaking visual alignment.
    Assert.Contains("| Header |", result);
    Assert.Contains("| ABC    |", result);
    Assert.Contains("| 你好   |", result);
}

[Fact]
public void FromDictionary_ShouldUseOuterDictionaryKeysAsRowLabelsInFirstColumn()
{
    var hierarchicalData = new Dictionary<string, Dictionary<string, object>>
    {
        {
            "RowLabel_Alpha", new Dictionary<string, object>
            {
                { "Column1", "Data1" },
                { "Column2", 10.5 }
            }
        },
        {
            "RowLabel_Beta", new Dictionary<string, object>
            {
                { "Column1", "Data2" },
                { "Column2", 20.5 }
            }
        }
    };

    var table = ConsoleTable.FromDictionary(hierarchicalData);

    Assert.Equal(string.Empty, table.Columns[0].ToString());
    Assert.Equal("RowLabel_Alpha", table.Rows[0][0]);
    Assert.Equal("RowLabel_Beta", table.Rows[1][0]);
    Assert.Equal("Data1", table.Rows[0][1]);
    Assert.Equal(20.5, table.Rows[1][2]);
}

