[Fact]
public void TableFormattingOptionsShouldBeConfigurableAndReflectedInOutput()
{
    var data = new[] { new { Value = 123 } };
    var table = ConsoleTable.From(data);

    // Exercise the configuration capability
    table.Configure(o =>
    {
        o.NumberAlignment = Alignment.Right;
        o.EnableCount = false;
    });

    var output = table.ToString();

    // Assert that the row count footer is missing as configured
    Assert.DoesNotContain("Count:", output);

    // Assert that numeric alignment is applied correctly.
    // Header 'Value' is 5 chars. Data '123' is 3 chars. 
    // Max column width is 5. '123' right-aligned in 5 chars is '  123'.
    // Adding default 1-char padding on each side results in '|   123 |'.
    Assert.Contains("|   123 |", output);
}

[Fact]
public void ShouldApplyUnicodeWidthsAndAlignmentAcrossMultipleFormats()
{
    // Arrange
    var users = new List<User>
    {
        new User { Name = "测试", Age = 99 }
    };

    var table = ConsoleTable.From(users)
        .Configure(o => o.NumberAlignment = Alignment.Right);

    // Act
    var markdownOutput = table.ToMarkDownString().Replace("\r\n", "\n");
    var defaultOutput = table.ToString().Replace("\r\n", "\n");
    var minimalOutput = table.ToMinimalString().Replace("\r\n", "\n");

    // Assert
    // 1. Unicode Support & Markdown Style: "测试" has a visual width of 4. 
    // "Age" has header width 3. "99" (width 2) right-aligned in width 3 results in " 99".
    Assert.Contains("| Name | Age |", markdownOutput);
    Assert.Contains("| 测试 |  99 |", markdownOutput);

    // 2. Default Grid Style Support
    Assert.Contains("Name", defaultOutput);
    Assert.Contains("测试", defaultOutput);
    Assert.Contains(" 99 ", defaultOutput);

    // 3. Minimal Style Support
    Assert.Contains("Name", minimalOutput);
    Assert.Contains("Age", minimalOutput);
    Assert.Contains("测试", minimalOutput);
    Assert.Contains("99", minimalOutput);
}

