[Fact]
public void PopulateFromVariousDataSourcesSpecificallyObjectArrays()
{
    var data = new object[][]
    {
        new object[] { "Name", "Score" },
        new object[] { "Alice", 95 },
        new object[] { "Bob", 82 }
    };

    var table = ConsoleTable.From(data);

    Assert.Equal(2, table.Columns.Count);
    Assert.Equal("Name", table.Columns[0]);
    Assert.Equal("Score", table.Columns[1]);
    Assert.Equal(2, table.Rows.Count);
    Assert.Equal("Alice", table.Rows[0][0]);
    Assert.Equal(82, table.Rows[1][1]);
}

[Fact]
public void AddRow_ShouldThrowException_WhenColumnsAreNotDefinedOrDataCountIsIncorrect()
{
    var table = new ConsoleTable();

    var firstException = Assert.Throws<Exception>(() => table.AddRow("RowWithoutColumns"));
    Assert.Equal("Please set the columns first", firstException.Message);

    table.AddColumn(new[] { "ColumnA", "ColumnB" });

    var secondException = Assert.Throws<Exception>(() => table.AddRow("MismatchCount"));
    Assert.Contains("does not match the values", secondException.Message);

    table.AddRow("DataA", "DataB");
}
